1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const PROCESSING_FEE = 5;
11	const DEDUCTIBLE = 100;
12	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
13	const SUBSEQUENT_CONTRACT_MULTIPLIER = 0.85;
14	const ALIKE_BUNDLE_DISCOUNT = 15;
15	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
19	const HIGH_ENCHANTMENT_CLAIM_FACTOR = 0.5;
20	const LOYALTY_DISCOUNT_MULTIPLIER = 0.8;
21	const LOYALTY_THRESHOLD = 2;
22	const COMPONENT_TYPES = ["rune", "moonstone"];
23	const DRAGON_MATERIAL = "dragon";
24	
25	type Item = { type: string; material?: string; cursed?: boolean; enchantment?: number };
26	
27	function ceilToWholeGold(amount: number): number {
28	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
29	}
30	
31	function basePremiumFor(itemType: string): number {
32	  return BASE_PREMIUMS[itemType] ?? 0;
33	}
34	
35	function enchantmentLevel(item: Item): number {
36	  return item.enchantment ?? 0;
37	}
38	
39	function isHighlyEnchanted(item: Item): boolean {
40	  return enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
41	}
42	
43	function qualifiesForHighEnchantmentClaim(item: Item | undefined): boolean {
44	  return item !== undefined && enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
45	}
46	
47	function itemPremium(item: Item): number {
48	  const base = basePremiumFor(item.type);
49	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
50	  const enchantmentMultiplier = isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER : 1;
51	  return base * cursedMultiplier * enchantmentMultiplier;
52	}
53	
54	function countOfType(items: Array<Item>, itemType: string): number {
55	  return items.filter((item) => item.type === itemType).length;
56	}
57	
58	function alikeBundleDiscount(items: Array<Item>): number {
59	  const bundleCount = COMPONENT_TYPES.reduce(
60	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
61	    0,
62	  );
63	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
64	}
65	
66	function contractHistoryMultiplierFor(previousQuotes: number): number {
67	  return previousQuotes >= 1 ? SUBSEQUENT_CONTRACT_MULTIPLIER : INITIAL_ASSESSMENT_MULTIPLIER;
68	}
69	
70	function loyaltyMultiplierFor(yearsWithMHPCO: number): number {
71	  return yearsWithMHPCO >= LOYALTY_THRESHOLD ? LOYALTY_DISCOUNT_MULTIPLIER : 1;
72	}
73	
74	export function quote(input: { items: Array<Item>; previousQuotes?: number; yearsWithMHPCO?: number }): number {
75	  const itemPremiumSum = input.items.reduce((sum, item) => sum + itemPremium(item), 0);
76	  const itemsTotal = itemPremiumSum - alikeBundleDiscount(input.items);
77	  const contractHistoryMultiplier = contractHistoryMultiplierFor(input.previousQuotes ?? 0);
78	  const loyaltyMultiplier = loyaltyMultiplierFor(input.yearsWithMHPCO ?? 0);
79	  const total = itemsTotal * contractHistoryMultiplier * loyaltyMultiplier + PROCESSING_FEE;
80	  return ceilToWholeGold(total);
81	}
