94	type QuoteStep = { op: "quote"; items: Array<Item> };
95	type ScenarioStep = QuoteStep;
96	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Array<ScenarioStep> };
97	
98	export function runScenario(scenario: Scenario): { results: Array<{ premium: number }> } {
99	  const results: Array<{ premium: number }> = [];
100	  let previousQuotes = 0;
101	  for (const step of scenario.steps) {
102	    if (step.op === "quote") {
103	      const premium = quote({
104	        items: step.items,
105	        yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
106	        previousQuotes,
107	      });
108	      results.push({ premium });
109	      previousQuotes += 1;
110	    }
111	  }
112	  return { results };
113	}
