115	export function claim(
116	  incident: { damages: Array<Damage> },
117	  policy: { items: Array<Item> },
118	): number {
119	  const totals = incident.damages.reduce(
120	    (acc, damage) => {
121	      const policyItem = policy.items.find((item) => item.type === damage.itemType);
122	      return isDragonMaterial(policyItem)
123	        ? { ...acc, dragon: acc.dragon + damage.amount }
124	        : { ...acc, other: acc.other + reimbursableAmount(damage, policyItem) };
125	    },
126	    { dragon: 0, other: 0 },
127	  );
128	  return totals.dragon + Math.max(0, totals.other - DEDUCTIBLE);
129	}
