export function runScenario(scenario: Scenario): { results: Array<{ premium: number }> } {
  const results = scenario.steps.map((step, index) => ({
    premium: quote({
      items: step.items,
      yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
      previousQuotes: index,
    }),
  }));
  return { results };
}
